import librosa
import numpy as np
from scipy.ndimage import maximum_filter
from collections import Counter

def get_peaks_adaptive(S_db, neighborhood_size=(21, 21), target_peaks_per_sec=30, sr=22050, hop_length=512):
    local_max = (maximum_filter(S_db, size=neighborhood_size) == S_db)
    local_max = local_max & (S_db > -70)

    freq_indices, time_indices = np.where(local_max)
    amplitudes = S_db[freq_indices, time_indices]

    sorted_indices = np.argsort(amplitudes)[::-1]

    num_frames = S_db.shape[1]
    duration = num_frames * hop_length / sr
    total_target_peaks = int(duration * target_peaks_per_sec)

    keep_indices = sorted_indices[:total_target_peaks]

    freq_peaks = freq_indices[keep_indices]
    time_peaks = time_indices[keep_indices]

    return list(zip(freq_peaks, time_peaks))

def generate_hashes(peaks, min_delta_t=1, max_delta_t=40, fan_out=5):
    peaks = sorted(peaks, key=lambda x: (x[1], x[0]))
    hashes = {}
    n_peaks = len(peaks)
    for i in range(n_peaks):
        f1, t1 = peaks[i]
        targets = []
        for j in range(i + 1, n_peaks):
            f2, t2 = peaks[j]
            dt = t2 - t1
            if dt < min_delta_t:
                continue
            if dt > max_delta_t:
                break
            targets.append((f2, t2, dt))

        for f2, t2, dt in targets[:fan_out]:
            key = (f1, f2, dt)
            if key not in hashes:
                hashes[key] = []
            hashes[key].append(t1)
    return hashes

def run_match(neighborhood_size, target_peaks_per_sec, fan_out, max_delta_t):
    d_y, d_sr = librosa.load('/workspace/database.wav', sr=None)
    q_y, q_sr = librosa.load('/workspace/query.wav', sr=None)

    n_fft = 2048
    hop_length = 512

    d_S = np.abs(librosa.stft(d_y, n_fft=n_fft, hop_length=hop_length))
    d_S_db = librosa.amplitude_to_db(d_S, ref=np.max)

    q_S = np.abs(librosa.stft(q_y, n_fft=n_fft, hop_length=hop_length))
    q_S_db = librosa.amplitude_to_db(q_S, ref=np.max)

    d_peaks = get_peaks_adaptive(d_S_db, neighborhood_size=neighborhood_size, target_peaks_per_sec=target_peaks_per_sec, sr=d_sr, hop_length=hop_length)
    q_peaks = get_peaks_adaptive(q_S_db, neighborhood_size=neighborhood_size, target_peaks_per_sec=target_peaks_per_sec, sr=q_sr, hop_length=hop_length)

    d_hashes = generate_hashes(d_peaks, max_delta_t=max_delta_t, fan_out=fan_out)
    q_hashes = generate_hashes(q_peaks, max_delta_t=max_delta_t, fan_out=fan_out)

    offsets = []
    for key, q_times in q_hashes.items():
        if key in d_hashes:
            d_times = d_hashes[key]
            for t_q in q_times:
                for t_d in d_times:
                    offsets.append(t_d - t_q)

    if not offsets:
        return None

    counter = Counter(offsets)
    most_common = counter.most_common(2)
    return most_common, len(offsets)

def main():
    # Try different configurations
    for nh_size in [(15, 15), (21, 21), (25, 25)]:
        for peaks_per_sec in [30, 40, 50]:
            for fan_out in [5, 10, 15]:
                for max_dt in [40, 60]:
                    res = run_match(nh_size, peaks_per_sec, fan_out, max_dt)
                    if res is None:
                        continue
                    most_common, total_matches = res
                    if len(most_common) >= 2:
                        top1, top2 = most_common[0], most_common[1]
                        ratio = top1[1] / top2[1] if top2[1] > 0 else top1[1]
                        print(f"NH: {nh_size}, P/S: {peaks_per_sec}, FO: {fan_out}, DT: {max_dt} -> Top 1: {top1[0]} ({top1[1]}), Top 2: {top2[0]} ({top2[1]}), Ratio: {ratio:.2f}, Total: {total_matches}")
                    else:
                        print(f"NH: {nh_size}, P/S: {peaks_per_sec}, FO: {fan_out}, DT: {max_dt} -> Top 1: {most_common[0]} (only 1 match)")

if __name__ == '__main__':
    main()

import librosa
import numpy as np
from scipy.ndimage import maximum_filter
from collections import Counter

def get_peaks_adaptive(S_db, neighborhood_size, target_peaks_per_sec, sr=22050, hop_length=512):
    local_max = (maximum_filter(S_db, size=neighborhood_size) == S_db)
    local_max = local_max & (S_db > -70)

    freq_indices, time_indices = np.where(local_max)
    amplitudes = S_db[freq_indices, time_indices]

    sorted_indices = np.argsort(amplitudes)[::-1]

    num_frames = S_db.shape[1]
    duration = num_frames * hop_length / sr
    total_target_peaks = int(duration * target_peaks_per_sec)

    keep_indices = sorted_indices[:min(total_target_peaks, len(sorted_indices))]

    freq_peaks = freq_indices[keep_indices]
    time_peaks = time_indices[keep_indices]

    return list(zip(freq_peaks, time_peaks))

def generate_hashes(peaks, min_delta_t=1, max_delta_t=45, fan_out=20):
    peaks = sorted(peaks, key=lambda x: (x[1], x[0]))
    hashes = {}
    n_peaks = len(peaks)
    for i in range(n_peaks):
        f1, t1 = peaks[i]
        targets = []
        for j in range(i + 1, n_peaks):
            f2, t2 = peaks[j]
            dt = t2 - t1
            if dt < min_delta_t:
                continue
            if dt > max_delta_t:
                break
            targets.append((f2, t2, dt))

        for f2, t2, dt in targets[:fan_out]:
            key = (f1, f2, dt)
            if key not in hashes:
                hashes[key] = []
            hashes[key].append(t1)
    return hashes

def main():
    d_y, d_sr = librosa.load('/workspace/database.wav', sr=None)
    q_y, q_sr = librosa.load('/workspace/query.wav', sr=None)

    n_fft = 2048
    hop_length = 512

    d_S = np.abs(librosa.stft(d_y, n_fft=n_fft, hop_length=hop_length))
    d_S_db = librosa.amplitude_to_db(d_S, ref=np.max)

    q_S = np.abs(librosa.stft(q_y, n_fft=n_fft, hop_length=hop_length))
    q_S_db = librosa.amplitude_to_db(q_S, ref=np.max)

    for nh_size in [(15, 15), (21, 21), (25, 25), (31, 31)]:
        for p_sec in [25, 30, 35, 40, 45]:
            for fo in [10, 15, 20, 25]:
                for max_dt in [35, 45, 55]:
                    d_peaks = get_peaks_adaptive(d_S_db, neighborhood_size=nh_size, target_peaks_per_sec=p_sec, sr=d_sr, hop_length=hop_length)
                    q_peaks = get_peaks_adaptive(q_S_db, neighborhood_size=nh_size, target_peaks_per_sec=p_sec, sr=q_sr, hop_length=hop_length)

                    d_hashes = generate_hashes(d_peaks, max_delta_t=max_dt, fan_out=fo)
                    q_hashes = generate_hashes(q_peaks, max_delta_t=max_dt, fan_out=fo)

                    offsets = []
                    for key, q_times in q_hashes.items():
                        if key in d_hashes:
                            d_times = d_hashes[key]
                            for t_q in q_times:
                                for t_d in d_times:
                                    offsets.append(t_d - t_q)

                    counter = Counter(offsets)
                    smoothed_counter = {}
                    for offset in counter:
                        smoothed_counter[offset] = counter[offset-1] + counter[offset] + counter[offset+1]

                    if not smoothed_counter:
                        continue

                    best_offset, best_count = max(smoothed_counter.items(), key=lambda x: x[1])

                    second_best_count = 0
                    for offset, count in smoothed_counter.items():
                        if abs(offset - best_offset) > 2:
                            if count > second_best_count:
                                second_best_count = count

                    ratio = best_count / second_best_count if second_best_count > 0 else best_count
                    if ratio > 2.8 and best_count > 30:
                        print(f"NH: {nh_size}, P/S: {p_sec}, FO: {fo}, DT: {max_dt} -> Best: {best_offset} ({best_count}), Ratio: {ratio:.2f}, Total: {len(offsets)}")

if __name__ == '__main__':
    main()
